312: func (t Tags) getSortTag(originalTag string, tagNames ...string) string {
313: 	formats := []string{"sort%s", "sort_%s", "sort-%s", "%ssort", "%s_sort", "%s-sort"}
314: 	all := []string{originalTag}
315: 	for _, tag := range tagNames {
316: 		for _, format := range formats {
317: 			name := fmt.Sprintf(format, tag)
318: 			all = append(all, name)
319: 		}
