// TestFullScanOfFixtureDirectory tests the complete scan pipeline with real audio files
func TestFullScanOfFixtureDirectory(t *testing.T) {
	ctx := context.Background()

	// Create mock repositories
	mfRepo := tests.CreateMockMediaFileRepo()
	albumRepo := tests.CreateMockAlbumRepo()
	artistRepo := tests.CreateMockArtistRepo()
	genreRepo := &tests.MockedGenreRepo{}

	ds := &tests.MockDataStore{
		MockedMediaFile: mfRepo,
		MockedAlbum:     albumRepo,
		MockedArtist:    artistRepo,
		MockedGenre:     genreRepo,
	}

	// Create scanner with mock datastore and empty playlists/cacheWarmer
	scanner := NewTagScanner(ds, &mockPlaylists{}, &mockCacheWarmer{})

	// Create a test library pointing to the fixtures directory
	lib := model.Library{
		ID:         1,
		Name:       "Test Library",
		Path:       "tests/fixtures",
		LastScanAt: time.Time{}, // First scan
	}

	// Run the scan
	progress := make(chan uint32, 100)
	changeCount, err := scanner.Scan(ctx, lib, false, progress)
	close(progress)

	if err != nil {
		t.Fatalf("Scan failed: %v", err)
	}

	// Verify that changes were detected
	if changeCount == 0 {
		t.Errorf("Expected changes to be detected, but got changeCount=0")
	}

	// Verify that media files were added to the database
	allFiles, err := mfRepo.GetAll()
	if err != nil {
		t.Fatalf("Failed to get all media files: %v", err)
	}

	if len(allFiles) == 0 {
		t.Fatal("Expected media files to be added to the database, but got none")
	}

	// Verify that at least one file has expected metadata
	hasValidFile := false
	for _, mf := range allFiles {
		// Test files should have basic metadata extracted
		if mf.Title != "" && mf.Path != "" {
			hasValidFile = true
			// Verify that the path is correctly set
			if !filepath.IsAbs(mf.Path) && mf.Path != "" {
				// Path should be relative to library root or absolute
				_, err := os.Stat(mf.Path)
				if err == nil || os.IsNotExist(err) {
					// File can be missing in fixtures but path should be valid format
					t.Logf("Found media file: %s (%s)", mf.Title, mf.Path)
				}
			}
			break
		}
	}

	if !hasValidFile {
		t.Errorf("Expected at least one media file with valid title and path, got: %+v", allFiles)
	}
}

// TestMetadataExtraction tests that metadata is correctly extracted from audio files
func TestMetadataExtraction(t *testing.T) {
	ctx := context.Background()

	mfRepo := tests.CreateMockMediaFileRepo()
	albumRepo := tests.CreateMockAlbumRepo()
	artistRepo := tests.CreateMockArtistRepo()

	ds := &tests.MockDataStore{
		MockedMediaFile: mfRepo,
		MockedAlbum:     albumRepo,
		MockedArtist:    artistRepo,
		MockedGenre:     &tests.MockedGenreRepo{},
	}

	scanner := NewTagScanner(ds, &mockPlaylists{}, &mockCacheWarmer{})

	lib := model.Library{
		ID:         1,
		Name:       "Test Library",
		Path:       "tests/fixtures",
		LastScanAt: time.Time{},
	}

	progress := make(chan uint32, 100)
	_, err := scanner.Scan(ctx, lib, false, progress)
	close(progress)

	if err != nil {
		t.Fatalf("Scan failed: %v", err)
	}

	allFiles, _ := mfRepo.GetAll()

	// Verify essential metadata fields are populated
	for _, mf := range allFiles {
		// Title should be set (either from tags or filename)
		if mf.Title == "" {
			t.Errorf("Media file has empty title: %s", mf.Path)
		}

		// Suffix should be extracted from file extension
		if mf.Suffix == "" {
			t.Errorf("Media file has empty suffix: %s", mf.Path)
		}

		// Library ID should be set correctly
		if mf.LibraryID != lib.ID {
			t.Errorf("Media file has wrong LibraryID: expected %d, got %d", lib.ID, mf.LibraryID)
		}

		// Timestamps should be set
		if mf.UpdatedAt.IsZero() {
			t.Errorf("Media file has zero UpdatedAt: %s", mf.Path)
		}
	}
}

// TestAlbumAndArtistCreation tests that album and artist records are created during scan
func TestAlbumAndArtistCreation(t *testing.T) {
