func (m *ExtendedMockMediaFileRepo) CountAll(options ...model.QueryOptions) (int64, error) {
	all, _ := m.GetAll()
	return int64(len(all)), nil
}

func (m *ExtendedMockMediaFileRepo) Search(q string, offset int, size int) (model.MediaFiles, error) {
	return model.MediaFiles{}, nil
}

