	lib := model.Library{
		ID:         1,
		Name:       "Test Library",
		Path:       "tests/fixtures",
		LastScanAt: time.Time{}, // First scan
	}

	// First scan
	progress := make(chan uint32, 100)
	changeCount1, err := scanner.Scan(ctx, lib, false, progress)
	close(progress)

	if err != nil {
		t.Fatalf("First scan failed: %v", err)
	}

	// Get the count of files from first scan
	filesAfterFirstScan, _ := mfRepo.GetAll()
	firstScanCount := len(filesAfterFirstScan)

	// Set the LastScanAt to current time to simulate that scan just completed
	lib.LastScanAt = time.Now().Add(-1 * time.Second)

	// Second scan without file modifications
	progress = make(chan uint32, 100)
	changeCount2, err := scanner.Scan(ctx, lib, false, progress)
	close(progress)

	if err != nil {
		t.Fatalf("Second scan failed: %v", err)
	}

	// Second scan should detect no changes since files haven't been modified
	if changeCount2 != 0 {
		t.Logf("Second scan detected %d changes (expected 0 for unchanged files)", changeCount2)
		// This is informational - it's ok if incremental scan doesn't optimize perfectly
	}

	// Verify files count hasn't changed
	filesAfterSecondScan, _ := mfRepo.GetAll()
	if len(filesAfterSecondScan) != firstScanCount {
		t.Errorf("Files count changed between scans: expected %d, got %d",
			firstScanCount, len(filesAfterSecondScan))
	}

	// Verify both scans found changes on first scan
	if changeCount1 == 0 {
		t.Errorf("First scan should detect changes, but got changeCount=0")
	}
}

