		LastScanAt: time.Time{},
	}

	progress := make(chan uint32, 100)
	// Scanner should complete without crashing even with invalid files
	changeCount, err := scanner.Scan(ctx, lib, false, progress)
	close(progress)

	// Scan may succeed or have errors, but it should not panic
	if err != nil {
		t.Logf("Scan with invalid files returned error: %v (expected behavior)", err)
	}

	t.Logf("Scan completed with changeCount=%d", changeCount)
}

// TestProgressTracking verifies that progress is reported during scan
func TestProgressTracking(t *testing.T) {
	ctx := context.Background()

	mfRepo := NewExtendedMockMediaFileRepo()
	albumRepo := tests.CreateMockAlbumRepo()

	ds := &tests.MockDataStore{
		MockedMediaFile: mfRepo,
		MockedAlbum:     albumRepo,
		MockedGenre:     &tests.MockedGenreRepo{},
	}

	scanner := NewTagScanner(ds, &mockPlaylists{}, &mockCacheWarmer{})

	lib := model.Library{
		ID:         1,
		Name:       "Test Library",
		Path:       "tests/fixtures",
		LastScanAt: time.Time{},
	}

	progress := make(chan uint32, 100)
	go func() {
		_, _ = scanner.Scan(ctx, lib, false, progress)
	}()

	// Collect progress reports
	progressCount := 0
	for count := range progress {
		progressCount++
		if count == 0 {
			t.Errorf("Progress channel reported 0 files")
		}
		if progressCount > 1000 {
			// Prevent infinite loop in case of bug
			break
		}
	}

	t.Logf("Received %d progress reports during scan", progressCount)
}

